"use client"

import * as React from "react"
import {
  ActionDataTable,
  type ActionDataTableBulkAction,
  type ActionDataTableRowAction,
  Badge,
  Button,
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  type ColumnDef,
  DataTable,
  Leaderboard,
  type LeaderboardItem,
  Meter,
  MetadataList,
  SegmentedControl,
  Separator,
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
  Tag,
  formatCurrency,
} from "@gunjo/ui"
import {
  IconArrowRight,
  IconCoin,
  IconHandStop,
  IconMessageDots,
} from "@tabler/icons-react"

import {
  CREDIT_VARIANT,
  type EmptyTruck,
  fitBand,
  fitLabel,
  type Load,
  LOADS,
  type MatchCandidate,
  MATCHES,
  TRUCKS,
} from "./data"

const TONE_BADGE: Record<
  "success" | "warning" | "destructive",
  "success" | "warning" | "destructive"
> = { success: "success", warning: "warning", destructive: "destructive" }

const LOAD_STATUS_VARIANT: Record<
  Load["status"],
  "secondary" | "info" | "warning" | "success"
> = {
  募集中: "info",
  商談中: "warning",
  返答待ち: "warning",
  成約: "success",
}

const yen = (n: number) => formatCurrency(n, { maximumFractionDigits: 0 })

// 求貨側の発→着セル
function Lane({ origin, dest }: { origin: string; dest: string }) {
  return (
    <span className="inline-flex items-center gap-1 whitespace-nowrap">
      <span className="font-medium">{origin}</span>
      <IconArrowRight className="size-3.5 shrink-0 text-muted-foreground" aria-hidden />
      <span className="font-medium">{dest}</span>
    </span>
  )
}

export function TruckMatchingConsole() {
  // 選択中の荷物（マッチング候補の起点）
  const [activeLoadId, setActiveLoadId] = React.useState<string>("L-2207")
  // 候補のうち選択中の空車（ペアリング詳細の右側）
  const [activeTruckId, setActiveTruckId] = React.useState<string | null>("T-101")
  // 一括オファー対象（ActionDataTable の選択）
  const [selectedLoadIds, setSelectedLoadIds] = React.useState<string[]>([])
  // 求貨/求車のどちらを起点に見るか
  const [side, setSide] = React.useState<"loads" | "trucks">("loads")

  const activeLoad = LOADS.find((l) => l.id === activeLoadId) ?? null
  const candidates = MATCHES[activeLoadId] ?? []
  const activeCandidate =
    candidates.find((c) => c.truckId === activeTruckId) ?? candidates[0] ?? null
  const activeTruck: EmptyTruck | null = activeCandidate
    ? TRUCKS.find((t) => t.id === activeCandidate.truckId) ?? null
    : null

  // 荷物を切り替えたら、その候補の先頭を自動選択
  const selectLoad = React.useCallback((id: string) => {
    setActiveLoadId(id)
    const next = MATCHES[id]?.[0]?.truckId ?? null
    setActiveTruckId(next)
  }, [])

  // ── 荷物（求貨）一覧：ActionDataTable（行選択＋一括オファー） ───────────
  const loadColumns = React.useMemo<ColumnDef<Load>[]>(
    () => [
      {
        accessorKey: "id",
        header: "案件",
        cell: ({ row }) => (
          <div className="flex flex-col">
            <span className="font-mono text-xs font-semibold">{row.original.id}</span>
            <span className="text-xs text-muted-foreground">{row.original.shipper}</span>
          </div>
        ),
      },
      {
        id: "lane",
        header: "発 → 着",
        cell: ({ row }) => <Lane origin={row.original.origin} dest={row.original.dest} />,
      },
      {
        accessorKey: "item",
        header: "品目 / 重量",
        cell: ({ row }) => (
          <div className="flex flex-col">
            <span>{row.original.item}</span>
            <span className="text-xs text-muted-foreground tabular-nums">
              {row.original.weightKg.toLocaleString()}kg・{row.original.pallets}P
            </span>
          </div>
        ),
      },
      {
        accessorKey: "truckReq",
        header: "車種",
        cell: ({ row }) => <Tag variant="outline">{row.original.truckReq}</Tag>,
      },
      {
        accessorKey: "pickupAt",
        header: "積込 → 着",
        cell: ({ row }) => (
          <div className="flex flex-col text-xs tabular-nums">
            <span>{row.original.pickupAt}</span>
            <span className="text-muted-foreground">着 {row.original.deliverBy}</span>
          </div>
        ),
      },
      {
        accessorKey: "askFareYen",
        header: "希望運賃",
        cell: ({ row }) => {
          const diff = row.original.askFareYen - row.original.marketFareYen
          const sign = diff > 0 ? "+" : ""
          return (
            <div className="flex flex-col items-end text-right">
              <span className="font-semibold tabular-nums">{yen(row.original.askFareYen)}</span>
              <span className="text-xs text-muted-foreground tabular-nums">
                相場比 {sign}
                {yen(diff)}
              </span>
            </div>
          )
        },
      },
      {
        accessorKey: "credit",
        header: "与信",
        cell: ({ row }) => (
          <Badge variant={CREDIT_VARIANT[row.original.credit]}>{row.original.credit}</Badge>
        ),
      },
      {
        accessorKey: "status",
        header: "状況",
        cell: ({ row }) => (
          <Badge variant={LOAD_STATUS_VARIANT[row.original.status]}>{row.original.status}</Badge>
        ),
      },
      {
        id: "fit",
        header: "候補",
        cell: ({ row }) => {
          const n = MATCHES[row.original.id]?.length ?? 0
          const top = MATCHES[row.original.id]?.[0]?.fit
          return n === 0 ? (
            <span className="text-xs text-muted-foreground">なし</span>
          ) : (
            <span className="text-xs tabular-nums">
              {n}件
              {top != null && (
                <span className="ml-1 text-muted-foreground">最大{top}%</span>
              )}
            </span>
          )
        },
      },
    ],
    []
  )

  const loadRowActions = React.useMemo<ActionDataTableRowAction<Load>[]>(
    () => [
      {
        id: "match",
        label: "候補を見る",
        icon: IconArrowRight,
        onSelect: (row) => selectLoad(row.id),
      },
      {
        id: "offer",
        label: "オファー",
        icon: IconHandStop,
        variant: "primary",
        disabled: (row) => (MATCHES[row.id]?.length ?? 0) === 0,
        disabledReason: "適合する空車候補がありません",
        onSelect: (row) => selectLoad(row.id),
      },
    ],
    [selectLoad]
  )

  const loadBulkActions = React.useMemo<ActionDataTableBulkAction<Load>[]>(
    () => [
      {
        id: "bulk-offer",
        label: "一括オファー",
        icon: IconHandStop,
        variant: "primary",
        onSelect: (rows) =>
          // デモ環境のため alert。本番は一括オファー API を呼ぶ。
          alert(`${rows.length}件の荷物に一括オファーを送信します:\n` + rows.map((r) => `${r.id} ${r.origin}→${r.dest}`).join("\n")),
      },
      {
        id: "bulk-export",
        label: "CSV出力",
        icon: IconCoin,
        variant: "outline",
        onSelect: (rows) => alert(`${rows.length}件を求貨リストとしてCSV出力します`),
      },
    ],
    []
  )

  // ── 空車（求車）一覧：DataTable（表示中心、行クリックで起点切替の余地） ──
  const truckColumns = React.useMemo<ColumnDef<EmptyTruck>[]>(
    () => [
      {
        accessorKey: "id",
        header: "車両",
        cell: ({ row }) => (
          <div className="flex flex-col">
            <span className="font-mono text-xs font-semibold">{row.original.id}</span>
            <span className="text-xs text-muted-foreground">{row.original.carrier}</span>
          </div>
        ),
      },
      {
        accessorKey: "truckType",
        header: "車種",
        cell: ({ row }) => <Tag variant="outline">{row.original.truckType}</Tag>,
      },
      { accessorKey: "location", header: "現在地" },
      {
        accessorKey: "availableFrom",
        header: "空き / 帰り便",
        cell: ({ row }) => (
          <div className="flex flex-col gap-1">
            <span className="text-xs tabular-nums">{row.original.availableFrom}〜</span>
            {row.original.isReturn ? (
              <Badge variant="info">帰り便 {row.original.preferredArea}</Badge>
            ) : (
              <span className="text-xs text-muted-foreground">希望 {row.original.preferredArea}</span>
            )}
          </div>
        ),
      },
      {
        accessorKey: "capacityKg",
        header: "積載",
        cell: ({ row }) => (
          <span className="tabular-nums">{row.original.capacityKg.toLocaleString()}kg</span>
        ),
      },
      {
        accessorKey: "rating",
        header: "実績",
        cell: ({ row }) => (
          <span className="tabular-nums">★ {row.original.rating.toFixed(1)}</span>
        ),
      },
    ],
    []
  )

  // ── マッチング候補：Leaderboard（適合度で事前ソート済み） ───────────────
  const leaderboardItems = React.useMemo<LeaderboardItem[]>(
    () =>
      candidates.map((c) => {
        const truck = TRUCKS.find((t) => t.id === c.truckId)
        const tone = fitBand(c.fit)
        return {
          id: c.truckId,
          label: (
            <span className="inline-flex items-center gap-2">
              <span className="font-mono text-xs">{c.truckId}</span>
              <span>{truck?.carrier}</span>
              <Tag variant="outline" size="sm">
                {truck?.truckType}
              </Tag>
            </span>
          ),
          sublabel: (
            <span className="text-xs text-muted-foreground">
              {c.reason}・回送 {c.deadheadKm}km
            </span>
          ),
          value: c.fit,
          valueLabel: (
            <span className="inline-flex items-center gap-1.5">
              <span className="tabular-nums font-semibold">{c.fit}%</span>
              <Badge variant={TONE_BADGE[tone]}>{fitLabel(c.fit)}</Badge>
            </span>
          ),
          fraction: c.fit / 100,
          tone,
          onSelect: () => setActiveTruckId(c.truckId),
        }
      }),
    [candidates]
  )

  return (
    <div className="flex flex-col gap-4">
      <SegmentedControl
        aria-label="起点の切替（求貨 / 求車）"
        options={[
          { value: "loads", label: "求貨（荷物）起点" },
          { value: "trucks", label: "求車（空車）起点" },
        ]}
        value={side}
        onValueChange={(v) => setSide(v as "loads" | "trucks")}
      />

      <div className="grid grid-cols-1 gap-4 xl:grid-cols-[minmax(0,1.55fr)_minmax(0,1fr)]">
        {/* 左：求貨／求車の一覧 */}
        <Card>
          <CardHeader className="pb-3">
            <CardTitle as="h2" className="text-base">
              {side === "loads" ? "荷物（求貨）一覧" : "空車（求車）一覧"}
            </CardTitle>
          </CardHeader>
          <CardContent className="pt-0">
            <Tabs value={side} onValueChange={(v) => setSide(v as "loads" | "trucks")}>
              <TabsList>
                <TabsTrigger value="loads">求貨 {LOADS.length}</TabsTrigger>
                <TabsTrigger value="trucks">求車 {TRUCKS.length}</TabsTrigger>
              </TabsList>
              <TabsContent value="loads" className="mt-4">
                <ActionDataTable<Load, unknown>
                  columns={loadColumns}
                  data={LOADS}
                  getRowId={(row) => row.id}
                  getRowLabel={(row) => `${row.id} ${row.origin}→${row.dest}`}
                  enableSelection
                  selectedIds={selectedLoadIds}
                  onSelectionChange={setSelectedLoadIds}
                  rowActions={loadRowActions}
                  rowActionsVariant="menu"
                  bulkActions={loadBulkActions}
                  onRowClick={(row) => selectLoad(row.id)}
                  getRowState={(row) => (row.id === activeLoadId ? "selected" : undefined)}
                  filter={{ columnId: "item", placeholder: "品目で絞り込み…" }}
                  pageSize={10}
                  labels={{
                    filterPlaceholder: "品目で絞り込み…",
                    noResults: "該当する荷物がありません",
                    selectedRows: (n) => `${n}件の荷物を選択中`,
                    bulkActions: "一括操作",
                    actions: "操作",
                  }}
                />
              </TabsContent>
              <TabsContent value="trucks" className="mt-4">
                <DataTable<EmptyTruck, unknown>
                  columns={truckColumns}
                  data={TRUCKS}
                  filter={{ columnId: "location", placeholder: "現在地で絞り込み…" }}
                  pageSize={10}
                  labels={{ noResults: "該当する空車がありません" }}
                />
              </TabsContent>
            </Tabs>
          </CardContent>
        </Card>

        {/* 右：マッチング候補（適合度ランキング） */}
        <Card>
          <CardHeader className="pb-3">
            <CardTitle as="h2" className="text-base">
              マッチング候補
            </CardTitle>
            {activeLoad && (
              <p className="text-xs text-muted-foreground">
                {activeLoad.id}（{activeLoad.origin}→{activeLoad.dest}）に適合する空車・おすすめ順
              </p>
            )}
          </CardHeader>
          <CardContent className="pt-0">
            {candidates.length > 0 ? (
              <Leaderboard
                label="適合度ランキング"
                items={leaderboardItems}
                max={100}
                selectedId={activeCandidate?.truckId}
                highlightTop={1}
                formatValue={(v) => `${v}%`}
              />
            ) : (
              <p className="rounded-md border border-dashed p-6 text-center text-sm text-muted-foreground">
                この荷物に適合する空車候補はありません
              </p>
            )}
          </CardContent>
        </Card>
      </div>

      {/* マッチ詳細・成約：荷物 × 空車のペアリングを並べて比較 */}
      {activeLoad && activeTruck && activeCandidate && (
        <MatchDetail load={activeLoad} truck={activeTruck} candidate={activeCandidate} />
      )}
    </div>
  )
}

// ── マッチの詳細・成約（荷物 × 空車の二面比較 — 既存コンポーネントに受け皿がなく自作） ──
function MatchDetail({
  load,
  truck,
  candidate,
}: {
  load: Load
  truck: EmptyTruck
  candidate: MatchCandidate
}) {
  const tone = fitBand(candidate.fit)
  const fareDiff = candidate.proposedFareYen - load.marketFareYen
  return (
    <Card>
      <CardHeader className="flex-row items-center justify-between gap-3 pb-3">
        <div className="flex items-center gap-3">
          <CardTitle as="h2" className="text-base">
            マッチ詳細・成約
          </CardTitle>
          <Badge variant={TONE_BADGE[tone]}>適合度 {candidate.fit}%（{fitLabel(candidate.fit)}）</Badge>
        </div>
        <div className="flex items-center gap-2">
          <Button variant="outline" size="sm">
            <IconMessageDots className="size-4" aria-hidden /> 運賃交渉
          </Button>
          <Button variant="primary" size="sm">
            <IconHandStop className="size-4" aria-hidden /> オファーする
          </Button>
        </div>
      </CardHeader>
      <CardContent className="pt-0">
        {/* 二面比較：荷物（求貨） ⟷ 空車（求車） */}
        <div className="grid grid-cols-1 gap-4 md:grid-cols-[minmax(0,1fr)_auto_minmax(0,1fr)] md:items-stretch">
          {/* 荷物側 */}
          <section className="rounded-lg border bg-card p-4" aria-label="荷物（求貨）">
            <div className="mb-2 flex items-center gap-2">
              <Badge variant="info">求貨</Badge>
              <span className="font-mono text-xs text-muted-foreground">{load.id}</span>
            </div>
            <p className="mb-1 text-sm font-semibold">
              <Lane origin={load.origin} dest={load.dest} />
            </p>
            <MetadataList
              variant="compact"
              items={[
                { label: "荷主", value: load.shipper },
                { label: "品目", value: load.item },
                { label: "重量 / 容積", value: `${load.weightKg.toLocaleString()}kg / ${load.volumeM3}m³` },
                { label: "車種条件", value: load.truckReq },
                { label: "積込", value: load.pickupAt },
                { label: "着", value: load.deliverBy },
              ]}
            />
          </section>

          {/* コネクタ */}
          <div className="flex flex-row items-center justify-center gap-2 md:flex-col">
            <Separator className="hidden md:block md:h-8 md:w-px" orientation="vertical" />
            <span className="rounded-full border bg-muted px-2 py-0.5 text-xs font-medium text-muted-foreground">
              {load.distanceKm}km
            </span>
            <Separator className="hidden md:block md:h-8 md:w-px" orientation="vertical" />
          </div>

          {/* 空車側 */}
          <section className="rounded-lg border bg-card p-4" aria-label="空車（求車）">
            <div className="mb-2 flex items-center gap-2">
              <Badge variant="success">求車</Badge>
              <span className="font-mono text-xs text-muted-foreground">{truck.id}</span>
            </div>
            <p className="mb-1 text-sm font-semibold">
              {truck.carrier}・{truck.driver}（★{truck.rating.toFixed(1)}）
            </p>
            <MetadataList
              variant="compact"
              items={[
                { label: "車種", value: truck.truckType },
                { label: "現在地", value: truck.location },
                { label: "空き", value: `${truck.availableFrom}〜` },
                { label: "希望エリア", value: truck.preferredArea },
                { label: "帰り便", value: truck.isReturn ? "○（復路）" : "—" },
                { label: "回送距離", value: `${candidate.deadheadKm}km` },
              ]}
            />
          </section>
        </div>

        <Separator className="my-4" />

        {/* 適合度の内訳（Meter）と運賃 */}
        <div className="grid grid-cols-1 gap-4 lg:grid-cols-[minmax(0,1.4fr)_minmax(0,1fr)]">
          <div>
            <h3 className="mb-2 text-sm font-semibold">適合度の内訳</h3>
            <div className="flex flex-col gap-3">
              {candidate.factors.map((f) => (
                <div key={f.label}>
                  <div className="mb-1 flex items-baseline justify-between gap-2">
                    <span className="text-sm font-medium">{f.label}</span>
                    <span className="text-xs text-muted-foreground">{f.detail}</span>
                  </div>
                  <Meter
                    value={Math.round(f.score * 100)}
                    max={100}
                    direction="higher-is-better"
                    target={70}
                    unit="%"
                    size="sm"
                    label={`${f.label}の適合度`}
                  />
                </div>
              ))}
            </div>
          </div>

          <div className="rounded-lg border bg-muted/40 p-4">
            <h3 className="mb-3 text-sm font-semibold">運賃</h3>
            <MetadataList
              items={[
                { label: "提示運賃", value: <span className="font-semibold tabular-nums">{yen(candidate.proposedFareYen)}</span> },
                { label: "荷主希望", value: <span className="tabular-nums">{yen(load.askFareYen)}</span> },
                { label: "相場", value: <span className="tabular-nums text-muted-foreground">{yen(load.marketFareYen)}</span> },
                {
                  label: "相場比",
                  value: (
                    <span
                      className={
                        "tabular-nums font-medium " +
                        (fareDiff >= 0 ? "text-success-strong" : "text-destructive")
                      }
                    >
                      {fareDiff > 0 ? "+" : ""}
                      {yen(fareDiff)}
                    </span>
                  ),
                },
              ]}
            />
          </div>
        </div>
      </CardContent>
    </Card>
  )
}
